from elasticsearch import Elasticsearch
import json
from datetime import datetime

es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

index_name = "logs"
doc_type = "_doc"

if not es.indices.exists(index=index_name):
    es.indices.create(index=index_name)

def index_document(doc_id, doc_content):
    doc = {
        "doc_id": doc_id,
        "timestamp": datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S'),
        "content": doc_content
    }
    res = es.index(index=index_name, doc_type=doc_type, id=doc_id, body=doc)
    return res['result']

def search_query(query):
    res = es.search(index=index_name, body={"query": {"match": {"content": query}}})
    return res["hits"]["hits"]

def log(log_message):
    index_document("log_{}".format(int(datetime.utcnow().timestamp())), log_message)

# Example usage
index_document("1", "This is the first log message")
index_document("2", "Second log message")
logs = search_query("message")  # This will return all documents containing "message" in their content field.
for log in logs:
    print(log["_source"])

# Example logging
